module top_module(
    input CLK,
    input EN,
    input TE,
    output ENCLK
);wire n2;
    reg EN_reg;

    always @ (posedge CLK, posedge TE) begin
        if (TE) begin
            EN_reg <= 1'b0;
        end else begin
            EN_reg <= EN;
        end
    end

  wire temp1_EN_reg = EN_reg;
  wire temp2_CLK = CLK;
  assign n2 = temp1_EN_reg & temp2_CLK;
    assign ENCLK = n2;

endmodule
